noncompliant:
// Noncompliant: explicit implementation makes method uncallable from derived class
public class Foo : IMyInterface
{
    void IMyInterface.Method() // Explicit implementation
    {
        // ...
    }
}

// Noncompliant: private implementation
public interface IMyInterface
{
    void Method();
}

public class Base : IMyInterface
{
    void IMyInterface.Method() { } // Explicit and private
}

compliant:
// Compliant: public implementation
public class Foo : IMyInterface
{
    public void Method() // Public implementation
    {
        // ...
    }
}

// Compliant: protected implementation allowing derived access
public class Base : IMyInterface
{
    protected virtual void Method() { }
    void IMyInterface.Method() => Method();
}
